import React, { useState, useEffect } from 'react';
import { useData } from '../../context/DataContext';
import { useAuth } from '../../context/AuthContext';

// --- ĐỊNH NGHĨA CÁC ROLE CÔNG VIỆC ---
const OP_ROLES = [
  { code: 'ST', label: 'Senior Teacher' },
  { code: 'TT', label: 'Tenured Teacher' },
  { code: 'CCS', label: 'Customer Care Specialist' },
  { code: 'CCO', label: 'Customer Care Officer' },
  { code: 'CCA', label: 'Customer Care Assistant' }
];

const REG_ROLES = [
  { code: 'FFM', label: 'Fresh Fit Moderator' },
  { code: 'FFS', label: 'Fresh Fit Staff' },
  { code: 'FFA', label: 'Fresh Fit Admin' }
];

const UBI_OPTIONS = [25, 50, 75, 100];

const StaffManager = () => {
  const { user } = useAuth(); // User hiện tại đang đăng nhập
  const { staffList, addStaff, deleteStaff, updatePassword, updateStaffInfo } = useData();
  
  // State thêm mới (Chỉ Chief)
  const [formData, setFormData] = useState({ name: '', username: '', password: '' });
  
  // State quản lý chế độ mở rộng (để xem chi tiết/sửa trên mobile)
  const [expandedId, setExpandedId] = useState(null);

  // --- KIỂM TRA QUYỀN HẠN (SYSTEM ROLE) ---
  const isChief = user?.role === 'chief';
  const isOp = user?.role === 'op';
  const isReg = user?.role === 'reg';

  // --- LOGIC XỬ LÝ ---

  // 1. Thêm nhân sự (Chỉ Chief)
  const handleAdd = (e) => {
    e.preventDefault();
    if (!isChief) return alert("Không có quyền thực hiện!");
    if (!formData.name || !formData.username || !formData.password) return;
    
    addStaff({ 
      ...formData, 
      role: 'staff', // System role mặc định
      jobTitles: [], // Danh sách chức danh công việc
      ubiBase: 0,
      ubiPercent: 0,
      remuneration: 0,
      remunerationStatus: 'None' // None, Pending, Approved
    });
    setFormData({ name: '', username: '', password: '' });
    alert("Đã tạo tài khoản thành công");
  };

  // 2. Xóa nhân sự
  const handleDelete = (id) => {
    if (!isChief) return alert("Chỉ Chief Administrator mới được xóa tài khoản!");
    if (window.confirm("Bạn có chắc chắn muốn xóa nhân sự này?")) deleteStaff(id);
  };

  // 3. Đổi mật khẩu
  const handleResetPassword = (id) => {
    if (!isChief) return alert("Chỉ Chief Administrator mới được đổi mật khẩu!");
    const newPass = prompt("Nhập mật khẩu mới:", "123456");
    if (newPass) updatePassword(id, newPass);
  };

  // 4. Cập nhật System Role (Bổ nhiệm Chief/Op/Reg) - SỬA LỖI: Cho phép Chief bổ nhiệm Chief khác
  const handleChangeSystemRole = (id, newRole) => {
    if (!isChief) return;
    if (window.confirm(`Bổ nhiệm nhân sự này làm ${newRole.toUpperCase()}?`)) {
        updateStaffInfo(id, { role: newRole });
    }
  };

  // 5. Cập nhật Job Titles (Op & Reg gán vị trí)
  const toggleJobTitle = (staff, roleCode, roleGroup) => {
    // Kiểm tra quyền
    if (roleGroup === 'OP' && !isOp && !isChief) return alert("Cần quyền Operational hoặc Chief!");
    if (roleGroup === 'REG' && !isReg && !isChief) return alert("Cần quyền Regulatory hoặc Chief!");

    const currentTitles = staff.jobTitles || [];
    let newTitles;
    if (currentTitles.includes(roleCode)) {
      newTitles = currentTitles.filter(t => t !== roleCode);
    } else {
      newTitles = [...currentTitles, roleCode];
    }
    updateStaffInfo(staff.id, { jobTitles: newTitles });
  };

  // 6. Xử lý UBI (Chief)
  const updateUBI = (id, field, value) => {
    if (!isChief) return;
    updateStaffInfo(id, { [field]: value });
  };

  // 7. Xử lý Remuneration (Op đề xuất, Chief duyệt)
  const updateRemuneration = (id, value) => {
    // Op và Chief đều có thể nhập số liệu
    if (!isOp && !isChief) return;
    updateStaffInfo(id, { remuneration: Number(value), remunerationStatus: 'Pending' });
  };

  const approveRemuneration = (id) => {
    if (!isChief) return;
    updateStaffInfo(id, { remunerationStatus: 'Approved' });
  };

  // --- RENDER COMPONENT CON: THẺ NHÂN VIÊN (CARD VIEW) ---
  // Sử dụng Card view thay vì Table để tối ưu cho cả Mobile và Web
  const StaffCard = ({ staff }) => {
    const isExpanded = expandedId === staff.id;

    // Tính toán hiển thị UBI
    const ubiAmount = staff.ubiBase && staff.ubiPercent 
      ? (Number(staff.ubiBase) * (Number(staff.ubiPercent) / 100)).toLocaleString('vi-VN') 
      : 0;

    return (
      <div style={{ 
        background: '#fff', 
        marginBottom: '15px', 
        borderRadius: '8px', 
        boxShadow: '0 2px 8px rgba(0,0,0,0.08)',
        border: staff.role === 'chief' ? '2px solid #003366' : '1px solid #eee',
        overflow: 'hidden'
      }}>
        {/* Header của Card: Luôn hiển thị thông tin cơ bản */}
        <div 
          onClick={() => setExpandedId(isExpanded ? null : staff.id)}
          style={{ 
            padding: '15px', 
            display: 'flex', 
            justifyContent: 'space-between', 
            alignItems: 'center', 
            cursor: 'pointer',
            background: isExpanded ? '#f8f9fa' : '#fff'
          }}
        >
          <div style={{display: 'flex', alignItems: 'center', gap: '10px'}}>
             <div style={{
               width: '40px', height: '40px', borderRadius: '50%', 
               background: staff.role === 'chief' ? '#003366' : '#e9ecef',
               color: staff.role === 'chief' ? '#fff' : '#333',
               display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 'bold'
             }}>
               {staff.name.charAt(0).toUpperCase()}
             </div>
             <div>
               <h4 style={{margin: 0, color: '#333'}}>{staff.name}</h4>
               <small style={{color: '#666'}}>@{staff.username} | {staff.role.toUpperCase()}</small>
             </div>
          </div>
          <div style={{fontSize: '0.8rem', textAlign: 'right'}}>
            {staff.jobTitles && staff.jobTitles.length > 0 && (
               <span style={{background: '#e3f2fd', color: '#0d47a1', padding: '2px 8px', borderRadius: '10px'}}>
                 {staff.jobTitles.join(', ')}
               </span>
            )}
            <div style={{marginTop: '4px', color: '#888'}}>{isExpanded ? 'Thu gọn ▲' : 'Chi tiết ▼'}</div>
          </div>
        </div>

        {/* Phần nội dung mở rộng: Chứa các công cụ quản lý */}
        {isExpanded && (
          <div style={{ padding: '20px', borderTop: '1px solid #eee' }}>
            
            {/* 1. SECTION: SYSTEM ADMIN (CHIEF ONLY) */}
            {isChief && (
              <div style={sectionStyle}>
                <h5 style={headerStyle}>👑 System Authority (Chief Only)</h5>
                <div style={gridStyle}>
                  <label>
                    Vai trò hệ thống:
                    <select 
                      value={staff.role} 
                      onChange={(e) => handleChangeSystemRole(staff.id, e.target.value)}
                      style={inputStyle}
                    >
                      <option value="staff">Staff</option>
                      <option value="op">Operational Admin</option>
                      <option value="reg">Regulatory Admin</option>
                      <option value="chief">Chief Administrator</option>
                    </select>
                  </label>
                  
                  <div style={{display: 'flex', gap: '5px', marginTop: 'auto'}}>
                     <button onClick={() => handleResetPassword(staff.id)} style={btnYellow}>Đổi Pass</button>
                     <button onClick={() => handleDelete(staff.id)} style={btnRed}>Xóa User</button>
                  </div>
                </div>
              </div>
            )}

            {/* 2. SECTION: UBI & SALARY (CHIEF ONLY) */}
            {isChief && (
              <div style={sectionStyle}>
                <h5 style={headerStyle}>💰 UBI & Lương định mức</h5>
                <div style={gridStyle}>
                  <label>
                    UBI Cơ bản (VNĐ):
                    <input 
                      type="number" 
                      value={staff.ubiBase || ''} 
                      onChange={(e) => updateUBI(staff.id, 'ubiBase', e.target.value)}
                      placeholder="Nhập số tiền..."
                      style={inputStyle}
                    />
                  </label>
                  <label>
                    Phần trăm (%):
                    <select 
                      value={staff.ubiPercent || 0} 
                      onChange={(e) => updateUBI(staff.id, 'ubiPercent', e.target.value)}
                      style={inputStyle}
                    >
                      <option value="0">0%</option>
                      {UBI_OPTIONS.map(opt => <option key={opt} value={opt}>{opt}%</option>)}
                    </select>
                  </label>
                </div>
                <div style={{marginTop: '10px', fontWeight: 'bold', color: '#28a745'}}>
                  Thực lãnh UBI: {ubiAmount} VNĐ
                </div>
              </div>
            )}

            {/* 3. SECTION: REMUNERATION (OP PROPOSE, CHIEF APPROVE) */}
            {(isOp || isChief) && (
              <div style={sectionStyle}>
                <h5 style={headerStyle}>💸 Thù lao (Remuneration)</h5>
                <div style={{display: 'flex', gap: '10px', alignItems: 'flex-end', flexWrap: 'wrap'}}>
                  <label style={{flex: 1}}>
                    Đề xuất (VNĐ):
                    <input 
                      type="number"
                      value={staff.remuneration || ''}
                      onChange={(e) => updateRemuneration(staff.id, e.target.value)}
                      placeholder="Nhập thù lao..."
                      style={inputStyle}
                      disabled={!isOp && !isChief} 
                    />
                  </label>
                  {isChief && (
                    <button 
                      onClick={() => approveRemuneration(staff.id)}
                      disabled={staff.remunerationStatus === 'Approved'}
                      style={staff.remunerationStatus === 'Approved' ? btnDisabled : btnGreen}
                    >
                      {staff.remunerationStatus === 'Approved' ? 'Đã duyệt' : 'Duyệt'}
                    </button>
                  )}
                  <span style={{
                    padding: '8px', 
                    borderRadius: '4px', 
                    fontSize: '0.9rem',
                    background: staff.remunerationStatus === 'Approved' ? '#d4edda' : '#fff3cd',
                    color: staff.remunerationStatus === 'Approved' ? '#155724' : '#856404'
                  }}>
                    {staff.remunerationStatus === 'Approved' ? 'Đã chấp thuận' : 'Chờ duyệt'}
                  </span>
                </div>
              </div>
            )}

            {/* 4. SECTION: OPERATIONAL ASSIGNMENT (OP & CHIEF) */}
            {(isOp || isChief) && (
              <div style={sectionStyle}>
                <h5 style={{...headerStyle, color: '#007bff'}}>🏢 Operational Roles (Xét vị trí)</h5>
                <div style={{display: 'flex', flexWrap: 'wrap', gap: '10px'}}>
                  {OP_ROLES.map(role => (
                    <label key={role.code} style={checkboxLabelStyle}>
                      <input 
                        type="checkbox" 
                        checked={(staff.jobTitles || []).includes(role.code)}
                        onChange={() => toggleJobTitle(staff, role.code, 'OP')}
                      />
                      {role.code} ({role.label})
                    </label>
                  ))}
                </div>
              </div>
            )}

            {/* 5. SECTION: REGULATORY ASSIGNMENT (REG & CHIEF) */}
            {(isReg || isChief) && (
              <div style={sectionStyle}>
                <h5 style={{...headerStyle, color: '#dc3545'}}>⚖️ Regulatory Roles (Xét vị trí)</h5>
                <div style={{display: 'flex', flexWrap: 'wrap', gap: '10px'}}>
                  {REG_ROLES.map(role => (
                    <label key={role.code} style={checkboxLabelStyle}>
                      <input 
                        type="checkbox" 
                        checked={(staff.jobTitles || []).includes(role.code)}
                        onChange={() => toggleJobTitle(staff, role.code, 'REG')}
                      />
                      {role.code} ({role.label})
                    </label>
                  ))}
                </div>
              </div>
            )}

            {/* Thông tin cơ bản chỉnh sửa nhanh */}
            {(isChief || isOp || isReg) && (
               <div style={{marginTop: '15px', paddingTop: '15px', borderTop: '1px dashed #ccc'}}>
                 <small style={{color: '#666'}}>Thông tin liên hệ (Edit):</small>
                 <div style={{display: 'flex', gap: '10px', marginTop: '5px'}}>
                    <input 
                      defaultValue={staff.phone} 
                      onBlur={(e) => updateStaffInfo(staff.id, {phone: e.target.value})} 
                      placeholder="SĐT" style={inputStyle}
                    />
                    <input 
                      defaultValue={staff.email} 
                      onBlur={(e) => updateStaffInfo(staff.id, {email: e.target.value})} 
                      placeholder="Email" style={inputStyle}
                    />
                 </div>
               </div>
            )}

          </div>
        )}
      </div>
    );
  };

  return (
    <div style={{ maxWidth: '1000px', margin: '0 auto', padding: '10px' }}>
      <h2 style={{color: '#003366', textAlign: 'center'}}>Quản lý & Phân quyền Nhân sự</h2>
      
      {/* Form thêm mới (Chỉ Chief thấy) */}
      {isChief && (
        <form onSubmit={handleAdd} style={{ marginBottom: '20px', padding: '20px', background: '#e3f2fd', borderRadius: '8px' }}>
          <h4 style={{marginTop: 0, color: '#003366'}}>+ Thêm nhân sự mới</h4>
          <div style={{display: 'flex', gap: '10px', flexWrap: 'wrap'}}>
            <input placeholder="Họ tên" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required style={mainInputStyle}/>
            <input placeholder="Username" value={formData.username} onChange={e => setFormData({...formData, username: e.target.value})} required style={mainInputStyle}/>
            <input placeholder="Password" type="password" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} required style={mainInputStyle}/>
            <button type="submit" style={{...btnGreen, flex: 1, minWidth: '100px'}}>Tạo mới</button>
          </div>
        </form>
      )}

      {/* Danh sách nhân viên */}
      <div>
        {staffList.map(staff => (
          <StaffCard key={staff.id} staff={staff} />
        ))}
        {staffList.length === 0 && <p style={{textAlign: 'center', color: '#888'}}>Chưa có nhân sự nào.</p>}
      </div>
    </div>
  );
};

// --- STYLES (CSS-in-JS Helper) ---
const sectionStyle = { marginBottom: '15px', padding: '10px', background: '#fcfcfc', borderRadius: '6px', border: '1px solid #f0f0f0' };
const headerStyle = { margin: '0 0 10px 0', fontSize: '0.95rem', textTransform: 'uppercase', borderBottom: '1px solid #eee', paddingBottom: '5px' };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: '10px' };
const inputStyle = { width: '100%', padding: '6px', borderRadius: '4px', border: '1px solid #ccc', marginTop: '4px', boxSizing: 'border-box' };
const mainInputStyle = { flex: '1 1 200px', padding: '10px', border: '1px solid #ccc', borderRadius: '4px' };
const checkboxLabelStyle = { display: 'flex', alignItems: 'center', gap: '5px', padding: '5px 10px', background: '#eee', borderRadius: '15px', fontSize: '0.85rem', cursor: 'pointer' };

const btnGreen = { background: '#28a745', color: 'white', border: 'none', padding: '8px 12px', borderRadius: '4px', cursor: 'pointer' };
const btnYellow = { background: '#ffc107', color: 'black', border: 'none', padding: '8px 12px', borderRadius: '4px', cursor: 'pointer' };
const btnRed = { background: '#dc3545', color: 'white', border: 'none', padding: '8px 12px', borderRadius: '4px', cursor: 'pointer' };
const btnDisabled = { background: '#ccc', color: '#666', border: 'none', padding: '8px 12px', borderRadius: '4px', cursor: 'not-allowed' };

export default StaffManager;
